function projectQuery(query, fields) {
  let projection = {};
  for (let field of fields) {
    if (query[field] !== null) {
      projection[field] = 1;
    }
  }
  return { $project: projection };
}

solutions.python:
class Solution:
  def projectQuery(self, query, fields):
    def is_optional(field):
      return field.startswith('_')

    projection = {}
    for field in fields:
      if query.get(field) is not None or not is_optional(field):
        projection[field] = 1
      else:
        projection[field] = 0

    return { "$project": projection }
